content:
{
  "sentences": [
    {
      "text": "我還會不太會說中文，但是我在慢慢學。",
      "pinyin": "Wǒ hái bù tài huì shuō Zhōngwén, dànshì wǒ zài mànmàn xué.",
      "pinyin_numeric": "wo3 hai2 bu4 tai4 hui4 shuo1 Zhong1wen2, dan4shi4 wo3 zai4 man4man4 xue2.",
      "translation_en": "I still can't speak Chinese very well, but I am learning slowly.",
      "translation_ko": "저는 아직 중국어를 잘 못 하지만, 천천히 배우고 있어요."
    },
    {
      "text": "他還會不太會寫字，可是已經進步很多了。",
      "pinyin": "Tā hái bù tài huì xiě zì, kěshì yǐjīng jìnbù hěn duō le.",
      "pinyin_numeric": "ta1 hai2 bu4 tai4 hui4 xie3 zi4, ke3shi4 yi3jing1 jin4bu4 hen3 duo1 le.",
      "translation_en": "He still can't write characters very well, but he has already improved a lot.",
      "translation_ko": "그는 아직 글자를 잘 쓰지 못하지만, 이미 많이 발전했어요."
    },
    {
      "text": "我妹妹還不太會騎腳踏車，她需要多練習。",
      "pinyin": "Wǒ mèimei hái bù tài huì qí jiǎotàchē, tā xūyào duō liànxí.",
      "pinyin_numeric": "wo3 mei4mei hai2 bu4 tai4 hui4 qi2 jiao3ta4che1, ta1 xu1yao4 duo1 lian4xi2.",
      "translation_en": "My younger sister still can't ride a bike very well; she needs more practice.",
      "translation_ko": "제 여동생은 아직 자전거를 잘 타지 못해요. 연습이 더 필요해요."
    },
    {
      "text": "你還會不太會煮菜嗎？要不要我教你？",
      "pinyin": "Nǐ hái bù tài huì zhǔ cài ma? Yào bù yào wǒ jiāo nǐ?",
      "pinyin_numeric": "ni3 hai2 bu4 tai4 hui4 zhu3 cai4 ma0? yao4 bu4 yao4 wo3 jiao1 ni3?",
      "translation_en": "Do you still not know how to cook very well? Do you want me to teach you?",
      "translation_ko": "아직 요리를 잘 못하세요? 제가 가르쳐 드릴까요?"
    },
    {
      "text": "我朋友還不太會游泳，所以他打算下個星期去學。",
      "pinyin": "Wǒ péngyou hái bù tài huì yóuyǒng, suǒyǐ tā dǎsuàn xià ge xīngqī qù xué.",
      "pinyin_numeric": "wo3 peng2you hai2 bu4 tai4 hui4 you2yong3, suo3yi3 ta1 da3suan4 xia4 ge4 xing1qi1 qu4 xue2.",
      "translation_en": "My friend still can't swim very well, so he plans to go learn next week.",
      "translation_ko": "제 친구는 아직 수영을 잘 못해서 다음 주에 배우러 갈 계획이에요."
    },
    {
      "text": "她還不太會說英文，可是她已經聽懂很多了。",
      "pinyin": "Tā hái bù tài huì shuō Yīngwén, kěshì tā yǐjīng tīng dǒng hěn duō le.",
      "pinyin_numeric": "ta1 hai2 bu4 tai4 hui4 shuo1 Ying1wen2, ke3shi4 ta1 yi3jing1 ting1 dong3 hen3 duo1 le.",
      "translation_en": "She still can't speak English very well, but she already understands a lot.",
      "translation_ko": "그녀는 아직 영어를 잘 말하지 못하지만, 이미 많이 알아들어요."
    },
    {
      "text": "我哥哥還不太會開車，他覺得開車很難。",
      "pinyin": "Wǒ gēge hái bù tài huì kāi chē, tā juéde kāi chē hěn nán.",
      "pinyin_numeric": "wo3 ge1ge hai2 bu4 tai4 hui4 kai1 che1, ta1 jue2de kai1 che1 hen3 nan2.",
      "translation_en": "My older brother still can't drive very well; he thinks driving is difficult.",
      "translation_ko": "제 오빠는 아직 운전을 잘 못해요. 운전이 어렵다고 생각해요."
    },
    {
      "text": "你還會不太會用這個手機嗎？我可以幫你。",
      "pinyin": "Nǐ hái bù tài huì yòng zhège shǒujī ma? Wǒ kěyǐ bāng nǐ.",
      "pinyin_numeric": "ni3 hai2 bu4 tai4 hui4 yong4 zhe4 ge4 shou3ji1 ma0? wo3 ke3yi3 bang1 ni3.",
      "translation_en": "Do you still not know how to use this phone very well? I can help you.",
      "translation_ko": "아직 이 핸드폰 사용을 잘 못하세요? 제가 도와드릴 수 있어요."
    },
    {
      "text": "他已經學了半年中文，可是還不太會寫字。",
      "pinyin": "Tā yǐjīng xué le bàn nián Zhōngwén, kěshì hái bù tài huì xiě zì.",
      "pinyin_numeric": "ta1 yi3jing1 xue2 le ban4 nian2 Zhong1wen2, ke3shi4 hai2 bu4 tai4 hui4 xie3 zi4.",
      "translation_en": "He has been studying Chinese for half a year, but he still can't write characters very well.",
      "translation_ko": "그는 중국어를 반 년 동안 배웠지만, 아직 글자를 잘 쓰지 못해요."
    },
    {
      "text": "我媽媽還不太會用電腦，她覺得很複雜。",
      "pinyin": "Wǒ māma hái bù tài huì yòng diànnǎo, tā juéde hěn fùzá.",
      "pinyin_numeric": "wo3 ma1ma hai2 bu4 tai4 hui4 yong4 dian4nao3, ta1 jue2de hen3 fu4za2.",
      "translation_en": "My mom still doesn't know how to use the computer very well; she thinks it's very complicated.",
      "translation_ko": "저희 엄마는 아직 컴퓨터 사용을 잘 못하세요. 너무 복잡하다고 생각하세요."
    }
  ]
}
